import { Component, inject, OnInit } from '@angular/core';
import { Title, Meta }          from '@angular/platform-browser';
import { ActivatedRoute }       from '@angular/router';

@Component({ selector: 'app-article', template: '<router-outlet/>' })
export class ArticleComponent implements OnInit {
  private title = inject(Title);
  private meta  = inject(Meta);
  private route = inject(ActivatedRoute);

  ngOnInit() {
    const article = this.route.snapshot.data['article'];

    // Set <title>
    this.title.setTitle(`${article.title} — LearnWithDeiva`);

    // Set / update meta tags
    this.meta.updateTag({ name: 'description',     content: article.summary });
    this.meta.updateTag({ property: 'og:title',    content: article.title });
    this.meta.updateTag({ property: 'og:description', content: article.summary });
    this.meta.updateTag({ property: 'og:image',    content: article.ogImage });
  }
}

import { DOCUMENT } from '@angular/common';
import { Component, inject, OnInit } from '@angular/core';

@Component({ selector: 'app-faq', templateUrl: './faq.component.html' })
export class FaqComponent implements OnInit {
  private doc = inject(DOCUMENT);

  ngOnInit() {
    const schema = {
      '@context': 'https://schema.org',
      '@type': 'FAQPage',
      mainEntity: [
        {
          '@type': 'Question',
          name: 'What is Angular Signals?',
          acceptedAnswer: { '@type': 'Answer', text: 'A reactive primitive for fine-grained updates.' }
        }
      ]
    };

    const script = this.doc.createElement('script');
    script.type = 'application/ld+json';
    script.textContent = JSON.stringify(schema);
    this.doc.head.appendChild(script);
  }
}

// app.config.ts
import { ApplicationConfig }      from '@angular/core';
import { provideRouter }          from '@angular/router';
import { routes }                 from './app.routes';

export const appConfig: ApplicationConfig = {
  providers: [
    provideRouter(routes)
    // PathLocationStrategy is the default — produces /angular/routing, not /#/angular/routing
  ]
};
